                         false, false);
   }
-
+  // Conservatively bail out if operands involve NSW multiplication by a large constant.
+  // Decomposition does not soundly handle signed-wrapping muls with large factors, which can
+  // lead to incorrect reasoning (e.g., chains of mul nsw by +/-5001000 under assumptions).
+  // Keep reasoning for small constants (<=255) to preserve existing i8 simplifications.
+  // Place this early in the function to avoid adding variables unnecessarily.
+  do {
+    auto hasBadNSWMulByLargeConst = [](Value *V) {
+      Value *X; ConstantInt *CI;
+      if (match(V, m_NSWMul(m_Value(X), m_ConstantInt(CI))) ||
+          match(V, m_NSWMul(m_ConstantInt(CI), m_Value(X)))) {
+        if (CI->getBitWidth() <= 64) {
+          int64_t K = CI->getSExtValue();
+          if (K < -255 || K > 255)
+            return true;
+        } else {
+          return true;
+        }
+      }
+      return false;
+    };
+    if (hasBadNSWMulByLargeConst(Op0) || hasBadNSWMulByLargeConst(Op1))
+      return ConstraintTy();
+  } while (false);
+  SmallVector<Value *> NewVariables;
   // If both operands are known to be non-negative, change signed predicates to
   // unsigned ones. This increases the reasoning effectiveness in combination
   // with the signed <-> unsigned transfer logic.
@@ -800,14 +823,12 @@ ConstraintTy ConstraintInfo::getConstraintForSolving(CmpInst::Predicate Pred,
       isKnownNonNegative(Op0, DL, /*Depth=*/MaxAnalysisRecursionDepth - 1) &&
       isKnownNonNegative(Op1, DL, /*Depth=*/MaxAnalysisRecursionDepth - 1))
     Pred = ICmpInst::getUnsignedPredicate(Pred);
-
-  SmallVector<Value *> NewVariables;
   ConstraintTy R = getConstraint(Pred, Op0, Op1, NewVariables);
   if (!NewVariables.empty())
     return {};
   return R;
-}

